body:
Thanks for taking the time to report this.

Can you attach an example that shows the issue?  (Must be openly licensed, ideally in test_regress format.)

`ExeUnit.v`:

```verilog
module ClockGate(
  input  io_E,
  input  io_CK,
  output io_Q
);
  assign io_Q = io_CK & io_E;
endmodule

module ExeUnit(
  input  clock,
  input  io_in_valid,
  output io_out_valid
);
  reg valid, valid_1, valid_2;
  wire clock_1;

  initial valid = 1'b0;
  initial valid_1 = 1'b0;
  initial valid_2 = 1'b0;

  ClockGate clkg(
    .io_E(valid | valid_1 | valid_2),
    .io_CK(clock),
    .io_Q(clock_1)
  );

  always @(posedge clock) valid <= io_in_valid;
  always @(posedge clock_1) valid_1 <= valid;
  always @(posedge clock_1) valid_2 <= valid_1;

  assign io_out_valid = valid_2;
endmodule
```

`sim_main.cpp`:

```cpp
#include "VExeUnit.h"
#include "verilated.h"
#include <verilated_vcd_c.h>	// Trace file format header

int main(int argc, char** argv) {
  int i = 0;
  VerilatedContext* contextp = new VerilatedContext;
  contextp->commandArgs(argc, argv);
  VExeUnit* top = new VExeUnit{contextp};
  VerilatedVcdC* tfp = new VerilatedVcdC;
  Verilated::traceEverOn(true);
  top->trace(tfp, 99);
  tfp->open("./wave.vcd");
  top->clock = 0;
  top->io_in_valid = 0;

  // reset
  top->clock = 1;
  top->eval();
  tfp->dump(i++);
  top->clock = 0;
  top->eval();
  tfp->dump(i++);
  top->clock = 1;
  top->eval();
  tfp->dump(i++);
  top->clock = 0;
  top->eval();
  tfp->dump(i++);

  top->clock = 1;
  top->eval();
  tfp->dump(i++);
  top->clock = 0;
  top->eval();
  tfp->dump(i++);

  top->io_in_valid = 1;
  top->clock = 1;
  top->eval();
  tfp->dump(i++);
  top->clock = 0;
  top->eval();
  tfp->dump(i++);

  top->io_in_valid = 0;
  top->clock = 1;
  top->eval();
  tfp->dump(i++);
  top->clock = 0;
  top->eval();
  tfp->dump(i++);
  top->clock = 1;
  top->eval();
  tfp->dump(i++);
  top->clock = 0;
  top->eval();
  tfp->dump(i++);
  top->clock = 1;
  top->eval();
  tfp->dump(i++);
  top->clock = 0;
  top->eval();
  tfp->dump(i++);

  // while (!contextp->gotFinish()) {
  //   top->clock = 1;
  //   top->eval();
  //   top->clock = 0;
  //   top->eval();
  //   top->in++;
  // }

  tfp->close();
  delete top;
  delete contextp;
  delete tfp;
  return 0;
}
```

When I compile and run by

```shell
verilator --cc --trace --exe --build -j 8 --top-module ExeUnit sim_main.cpp ExeUnit.v && ./obj_dir/VExeUnit
```

It produces `wave.vcd` which displays like:

<img width="605" alt="1701945382907" src="https://github.com/verilator/verilator/assets/46089480/6793ae4b-bc98-45cc-84f6-732759bea645">

Here, `valid_1` and `valid` are set simultaneously, which I think may not be correct. `valid_1` may be set a cycle later than `valid`.

What 'verilator --version' are you using?  Did you try it with the git master version?

